import{_ as e,o as t,c as o,a}from"./app.3b996310.js";const u=JSON.parse('{"title":"gbrb v. bgbba, Jun 2018","description":"","frontmatter":{},"headers":[{"level":2,"title":"Case","slug":"case","link":"#case","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]}],"relativePath":"government/court-cases-precedents/gbrb_v_bgbba_jun_2018.md","lastUpdated":1666477380000}'),r={name:"government/court-cases-precedents/gbrb_v_bgbba_jun_2018.md"},n=a('<h1 id="gbrb-v-bgbba-jun-2018" tabindex="-1">gbrb v. bgbba, Jun 2018 <a class="header-anchor" href="#gbrb-v-bgbba-jun-2018" aria-hidden="true">#</a></h1><h2 id="case" tabindex="-1">Case <a class="header-anchor" href="#case" aria-hidden="true">#</a></h2><p>With meat312 presiding, on 7th June 2018, gbrb charged bgbba with Negligence. bgbba plead guilty and was ordered to pay 10 diamonds in restitution.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><p><strong>gbrb</strong>:</p><blockquote><p>I am suing bgbba for failure to ensure the safety of the Great Eastern Railway. fire from a blaze spawner within range of the rails led to the death of my parrot</p></blockquote><p><strong>meat312</strong>:</p><blockquote><p>bgbba may choose me or Wing to preside.</p></blockquote><p><strong>bgbba</strong>:</p><blockquote><p>So, what do you want exactly? Make your case bro</p></blockquote><p><strong>gbrb</strong>:</p><blockquote><p>I want compensation for the loss of the parrot, and a solution to prevent further incidents</p></blockquote><p><strong>meat312</strong>:</p><blockquote><p>how much in material worth?</p></blockquote><p><strong>gbrb</strong>:</p><blockquote><p>isn&#39;t that up to the judge to decide?</p></blockquote><p><strong>meat312</strong>:</p><blockquote><p>You can leave that to me if you like</p></blockquote><p><strong>gbrb</strong>:</p><blockquote><p>Attached is a screenshot from where the incident took place, as you can see it looks more like a scene from an apocalypse than a safe railway.</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/454100979298861057/2018-06-07_02.53.02.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/454100979298861057/2018-06-07_02.53.02.png</a></p></blockquote><p><strong>bgbba</strong>:</p><blockquote><p>Oh, that part</p></blockquote><blockquote><p>Yeah lmao, I forgot to finish fixing that part up</p></blockquote><blockquote><p>Yeah, I plead guilty here, I&#39;ll just fix the railroad and toss you a few diamonds so you can find a new parrot (there are a few untamed ones north of CW on the railroad)</p></blockquote><p><strong>meat312</strong>:</p><blockquote><p>Perfect I award gbrb the sum of 10D in damages, and Bg will remove the blaze hazard on the rail line in that location.</p></blockquote>',27),s=[n];function b(c,p,i,l,d,g){return t(),o("div",null,s)}const _=e(r,[["render",b]]);export{u as __pageData,_ as default};
